import styled from "styled-components";
import { TailsInterface } from "./types";
import { getColors } from "../../Styles/colors";

export const Tails = styled.div<TailsInterface>`
  border: 5px solid ${({ theme }) => getColors(theme).text};
  width: 10rem;
  box-sizing: border-box;
  margin-bottom: 1rem;
`;

export const Container = styled.div`
  margin: 2rem;
  color: ${({ theme }) => getColors(theme).text};
  display: flex;
  justify-content: center;
`;

export const Body = styled.div`
  border: 5px solid ${({ theme }) => getColors(theme).text};
  width: min-content;
  white-space: nowrap;
  padding: 2rem 4rem;
  font-size: 1.5rem;
  box-sizing: border-box;
  margin-top: 1rem;
  position: absolute;
`;

export const Spacer = styled.div`
  border: 5px solid transparent;
  background-color: ${({ theme }) => getColors(theme).background};
  width: min-content;
  white-space: nowrap;
  padding: 2rem;
  font-size: 1.5rem;
  box-sizing: border-box;
  opacity: 0;
`;
